generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model Task {
  id          String   @id @default(cuid())
  title       String
  description String?
  dueDate     DateTime?
  completed   Boolean  @default(false)
  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt
}

import { PrismaClient } from '@prisma/client'

const globalForPrisma = globalThis as unknown as {
  prisma: PrismaClient | undefined
}

export const prisma = globalForPrisma.prisma ?? new PrismaClient()

if (process.env.NODE_ENV !== 'production') globalForPrisma.prisma = prisma

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

export async function GET() {
  const tasks = await prisma.task.findMany({
    orderBy: { createdAt: 'desc' }
  })
  return NextResponse.json(tasks)
}

export async function POST(request: NextRequest) {
  const body = await request.json()
  const task = await prisma.task.create({
    data: {
      title: body.title,
      description: body.description,
      dueDate: body.dueDate ? new Date(body.dueDate) : null,
      completed: body.completed ?? false
    }
  })
  return NextResponse.json(task, { status: 201 })
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

export async function GET(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  const task = await prisma.task.findUnique({
    where: { id: params.id }
  })
  if (!task) {
    return NextResponse.json({ error: 'Task not found' }, { status: 404 })
  }
  return NextResponse.json(task)
}

export async function PUT(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  const body = await request.json()
  const task = await prisma.task.update({
    where: { id: params.id },
    data: {
      title: body.title,
      description: body.description,
      dueDate: body.dueDate ? new Date(body.dueDate) : null,
      completed: body.completed
    }
  })
  return NextResponse.json(task)
}

export async function DELETE(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  await prisma.task.delete({
    where: { id: params.id }
  })
  return NextResponse.json({ message: 'Task deleted' })
}

'use client'

import { useState, useEffect } from 'react'
import { Button, Card, Checkbox, Input, DatePicker, Modal, Form, message } from 'antd'
import { PlusOutlined, DeleteOutlined, EditOutlined } from '@ant-design/icons'
import dayjs from 'dayjs'

interface Task {
  id: string
  title: string
  description: string | null
  dueDate: string | null
  completed: boolean
}

export default function Home() {
  const [tasks, setTasks] = useState<Task[]>([])
  const [loading, setLoading] = useState(true)
  const [modalOpen, setModalOpen] = useState(false)
  const [editingTask, setEditingTask] = useState<Task | null>(null)
  const [form] = Form.useForm()

  useEffect(() => {
    fetchTasks()
  }, [])

  const fetchTasks = async () => {
    try {
      const res = await fetch('/api/tasks')
      const data = await res.json()
      setTasks(data)
    } catch {
      message.error('Failed to load tasks')
    } finally {
      setLoading(false)
    }
  }

  const handleSubmit = async (values: any) => {
    try {
      const payload = {
        title: values.title,
        description: values.description,
        dueDate: values.dueDate?.toISOString(),
        completed: values.completed ?? false
      }

      if (editingTask) {
        await fetch(`/api/tasks/${editingTask.id}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        })
        message.success('Task updated')
      } else {
        await fetch('/api/tasks', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        })
        message.success('Task created')
      }

      setModalOpen(false)
      setEditingTask(null)
      form.resetFields()
      fetchTasks()
    } catch {
      message.error('Failed to save task')
    }
  }

  const handleDelete = async (id: string) => {
    try {
      await fetch(`/api/tasks/${id}`, { method: 'DELETE' })
      message.success('Task deleted')
      fetchTasks()
    } catch {
      message.error('Failed to delete task')
    }
  }

  const handleToggleComplete = async (task: Task) => {
    try {
      await fetch(`/api/tasks/${task.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...task, completed: !task.completed })
      })
      fetchTasks()
    } catch {
      message.error('Failed to update task')
    }
  }

  return (
    <div style={{ maxWidth: 800, margin: '0 auto', padding: 24 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
        <h1>Task Manager</h1>
        <Button type="primary" icon={<PlusOutlined />} onClick={() => { setEditingTask(null); form.resetFields(); setModalOpen(true) }}>
          Add Task
        </Button>
      </div>

      {loading ? (
        <p>Loading...</p>
      ) : tasks.length === 0 ? (
        <Card><p style={{ textAlign: 'center', color: '#999' }}>No tasks yet. Create one to get started!</p></Card>
      ) : (
        tasks.map(task => (
          <Card
            key={task.id}
            style={{ marginBottom: 8 }}
            actions={[
              <EditOutlined key="edit" onClick={() => { setEditingTask(task); form.setFieldsValue({ ...task, dueDate: task.dueDate ? dayjs(task.dueDate) : null }); setModalOpen(true) }} />,
              <DeleteOutlined key="delete" onClick={() => handleDelete(task.id)} />
            ]}
          >
            <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
              <Checkbox checked={task.completed} onChange={() => handleToggleComplete(task)} />
              <div style={{ flex: 1 }}>
                <h3 style={{ textDecoration: task.completed ? 'line-through' : 'none', margin: 0 }}>{task.title}</h3>
                {task.description && <p style={{ margin: '4px 0 0', color: '#666' }}>{task.description}</p>}
                {task.dueDate && <p style={{ margin: '4px 0 0', fontSize: 12, color: '#999' }}>Due: {new Date(task.dueDate).toLocaleDateString()}</p>}
              </div>
            </div>
          </Card>
        ))
      )}

      <Modal
        title={editingTask ? 'Edit Task' : 'New Task'}
        open={modalOpen}
        onCancel={() => { setModalOpen(false); setEditingTask(null); form.resetFields() }}
        onOk={() => form.submit()}
      >
        <Form form={form} layout="vertical" onFinish={handleSubmit}>
          <Form.Item name="title" label="Title" rules={[{ required: true, message: 'Please enter a title' }]}>
            <Input placeholder="Task title" />
          </Form.Item>
          <Form.Item name="description" label="Description">
            <Input.TextArea placeholder="Task description" rows={3} />
          </Form.Item>
          <Form.Item name="dueDate" label="Due Date">
            <DatePicker style={{ width: '100%' }} />
          </Form.Item>
          <Form.Item name="completed" label="Completed" valuePropName="checked">
            <Checkbox>Mark as completed</Checkbox>
          </Form.Item>
        </Form>
      </Modal>
    </div>
  )
}

import type { Metadata } from 'next'
import { AntdRegistry } from '@ant-design/nextjs-registry'
import './globals.css'

export const metadata: Metadata = {
  title: 'Task Manager',
  description: 'A simple task management application',
}

export default function RootLayout({
  children,
}: {
  children: React.ReactNode
}) {
  return (
    <html lang="en">
      <body>
        <AntdRegistry>{children}</AntdRegistry>
      </body>
    </html>
  )
}

body {
  margin: 0;
  padding: 0;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
}

/** @type {import('next').NextConfig} */
const nextConfig = {
  output: "standalone",
  eslint: {
    ignoreDuringBuilds: true,
  },
  typescript: {
    ignoreBuildErrors: false,
  },
}

export default nextConfig
